def hashcode(n: int) -> str:
    return hashlib.sha256(str(n).encode('utf-8')).hexdigest()

@pytest.mark.parametrize("inputs, result, testcase", q6_testcases)
def test_q6(monkeypatch, inputs, result, testcase):
    simulated_inputs = iter(inputs)
    monkeypatch.setattr('builtins.input', lambda: next(simulated_inputs))
    output = eval(pprint.pformat(contacts()))
    if testcase == True:
        assert output == result
    else:
        assert hashcode(output) == result